import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { FetchFunction, Resolvable } from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  convertBase64ToUint8Array,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  resolve,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { PixelArtImageModelId } from './pixelart-image-settings';
import { pixelArtImageModelOptionsSchema } from './pixelart-image-options';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

// Response schema — kept minimal so the model is resilient to API changes.
const pixelArtImageResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      created: z.number().nullish(),
      data: z.array(
        z.object({
          b64_json: z.string(),
          revised_prompt: z.string().nullish(),
        }),
      ),
    }),
  ),
);

// Error schema for the PixelArt API error envelope.
const pixelArtErrorSchema = z.object({
  error: z.object({
    message: z.string(),
    type: z.string().nullish(),
    code: z.string().nullish(),
  }),
});

const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: error => error.error.message,
});

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';

  /**
   * The PixelArt API allows up to 4 images per generation request.
   */
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const {
      prompt,
      n,
      size,
      aspectRatio,
      seed,
      providerOptions,
      headers,
      abortSignal,
    } = options;

    const warnings: Array<SharedV3Warning> = [];

    // PixelArt uses explicit pixel dimensions; aspect-ratio shorthand is
    // not supported by the API.
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support aspect ratio. Use `size` instead (e.g. "256x256").',
      });
    }

    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const requestBody: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n,
    };

    if (size != null) {
      requestBody.size = size;
    }

    if (seed != null) {
      requestBody.seed = seed;
    }

    if (pixelArtOptions?.style != null) {
      requestBody.style = pixelArtOptions.style;
    }

    if (pixelArtOptions?.pixelDensity != null) {
      requestBody.pixel_density = pixelArtOptions.pixelDensity;
    }

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(await resolve(this.config.headers), headers),
      body: requestBody,
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(item =>
        convertBase64ToUint8Array(item.b64_json),
      ),
      warnings,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelart: {
          created: response.created ?? undefined,
        },
      },
    };
  }
}

