import { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const TEST_PROMPT = 'A tiny dragon in a pixel art forest';

// A minimal 1×1 transparent PNG encoded as base64.
const FAKE_B64_IMAGE =
  'iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==';

function createModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: Record<string, string | undefined>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('pixelart-v1', {
    provider: 'pixelart.image',
    baseURL: 'https://api.example.com/v1',
    headers: headers ?? { Authorization: 'Bearer test-key' },
    fetch,
    _internal: { currentDate },
  });
}

function makeSuccessBody(n = 1) {
  return {
    created: 1700000000,
    data: Array.from({ length: n }, () => ({ b64_json: FAKE_B64_IMAGE })),
  };
}

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    'https://api.example.com/v1/images/generate': {
      response: {
        type: 'json-value',
        body: makeSuccessBody(),
      },
    },
  });

  // -------------------------------------------------------------------------
  // Constructor / metadata
  // -------------------------------------------------------------------------
  describe('constructor', () => {
    it('exposes correct provider, modelId, and spec version', () => {
      const model = createModel();
      expect(model.provider).toBe('pixelart.image');
      expect(model.modelId).toBe('pixelart-v1');
      expect(model.specificationVersion).toBe('v3');
      expect(model.maxImagesPerCall).toBe(4);
    });
  });

  // -------------------------------------------------------------------------
  // Request body construction
  // -------------------------------------------------------------------------
  describe('doGenerate — request body', () => {
    it('sends model, prompt, n, and size', async () => {
      const model = createModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 2,
        size: '256x256',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-v1',
        prompt: TEST_PROMPT,
        n: 2,
        size: '256x256',
      });
    });

    it('omits size when not provided', async () => {
      const model = createModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).not.toHaveProperty('size');
    });

    it('sends seed when provided', async () => {
      const model = createModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: 42,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect((await server.calls[0].requestBodyJson).seed).toBe(42);
    });

    it('omits seed when not provided', async () => {
      const model = createModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).not.toHaveProperty('seed');
    });

    it('sends style provider option as-is', async () => {
      const model = createModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: '128x128',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: { pixelart: { style: 'retro' } },
        files: undefined,
        mask: undefined,
      });

      expect((await server.calls[0].requestBodyJson).style).toBe('retro');
    });

    it('sends pixel_density (camelCase → snake_case) provider option', async () => {
      const model = createModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: '256x256',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: { pixelart: { pixelDensity: 7 } },
        files: undefined,
        mask: undefined,
      });

      expect((await server.calls[0].requestBodyJson).pixel_density).toBe(7);
    });

    it('sends both style and pixel_density together', async () => {
      const model = createModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: '512x512',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: { pixelart: { style: '8bit', pixelDensity: 3 } },
        files: undefined,
        mask: undefined,
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body.style).toBe('8bit');
      expect(body.pixel_density).toBe(3);
    });

    it('omits style and pixel_density when not provided', async () => {
      const model = createModel();

      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).not.toHaveProperty('style');
      expect(body).not.toHaveProperty('pixel_density');
    });

    it('passes custom headers from provider and request', async () => {
      const model = createModel({
        headers: { 'X-Provider-Header': 'provider-value' },
      });

      await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        headers: { 'X-Request-Header': 'request-value' },
        files: undefined,
        mask: undefined,
      });

      expect(server.calls[0].requestHeaders).toMatchObject({
        'x-provider-header': 'provider-value',
        'x-request-header': 'request-value',
      });
    });
  });

  // -------------------------------------------------------------------------
  // Warnings
  // -------------------------------------------------------------------------
  describe('doGenerate — warnings', () => {
    it('emits unsupported warning for aspectRatio', async () => {
      const model = createModel();

      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: '16:9',
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.warnings).toHaveLength(1);
      expect(result.warnings[0]).toMatchObject({
        type: 'unsupported',
        feature: 'aspectRatio',
      });
    });

    it('emits no warnings when all parameters are valid', async () => {
      const model = createModel();

      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: '256x256',
        aspectRatio: undefined,
        seed: 1,
        providerOptions: { pixelart: { style: 'pixel', pixelDensity: 5 } },
        files: undefined,
        mask: undefined,
      });

      expect(result.warnings).toHaveLength(0);
    });
  });

  // -------------------------------------------------------------------------
  // Response handling
  // -------------------------------------------------------------------------
  describe('doGenerate — response', () => {
    it('returns images as Uint8Array instances', async () => {
      server.urls[
        'https://api.example.com/v1/images/generate'
      ].response = {
        type: 'json-value',
        body: makeSuccessBody(1),
      };

      const model = createModel();
      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.images).toHaveLength(1);
      expect(result.images[0]).toBeInstanceOf(Uint8Array);
    });

    it('returns multiple images when n > 1', async () => {
      server.urls[
        'https://api.example.com/v1/images/generate'
      ].response = {
        type: 'json-value',
        body: makeSuccessBody(3),
      };

      const model = createModel();
      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 3,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.images).toHaveLength(3);
      result.images.forEach(img => expect(img).toBeInstanceOf(Uint8Array));
    });

    it('includes timestamp, modelId, and headers in response metadata', async () => {
      const testDate = new Date('2024-06-01T12:00:00Z');
      const model = createModel({ currentDate: () => testDate });

      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.response).toStrictEqual({
        timestamp: testDate,
        modelId: 'pixelart-v1',
        headers: expect.any(Object),
      });
    });

    it('includes created timestamp in providerMetadata', async () => {
      server.urls[
        'https://api.example.com/v1/images/generate'
      ].response = {
        type: 'json-value',
        body: { created: 1717234567, data: [{ b64_json: FAKE_B64_IMAGE }] },
      };

      const model = createModel();
      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.providerMetadata).toStrictEqual({
        pixelart: { created: 1717234567 },
      });
    });

    it('sets created to undefined when missing from response', async () => {
      server.urls[
        'https://api.example.com/v1/images/generate'
      ].response = {
        type: 'json-value',
        body: { data: [{ b64_json: FAKE_B64_IMAGE }] },
      };

      const model = createModel();
      const result = await model.doGenerate({
        prompt: TEST_PROMPT,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.providerMetadata?.pixelart?.created).toBeUndefined();
    });
  });

  // -------------------------------------------------------------------------
  // Error handling
  // -------------------------------------------------------------------------
  describe('doGenerate — errors', () => {
    it('throws an error with the API message on 400', async () => {
      server.urls[
        'https://api.example.com/v1/images/generate'
      ].response = {
        type: 'error',
        status: 400,
        body: JSON.stringify({
          error: {
            message: 'Invalid prompt: content policy violation',
            type: 'invalid_request_error',
            code: 'content_policy',
          },
        }),
      };

      const model = createModel();
      await expect(
        model.doGenerate({
          prompt: TEST_PROMPT,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
          files: undefined,
          mask: undefined,
        }),
      ).rejects.toMatchObject({
        message: 'Invalid prompt: content policy violation',
        statusCode: 400,
      });
    });

    it('throws an error on 401 unauthorized', async () => {
      server.urls[
        'https://api.example.com/v1/images/generate'
      ].response = {
        type: 'error',
        status: 401,
        body: JSON.stringify({
          error: { message: 'Invalid API key', type: 'authentication_error' },
        }),
      };

      const model = createModel();
      await expect(
        model.doGenerate({
          prompt: TEST_PROMPT,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
          files: undefined,
          mask: undefined,
        }),
      ).rejects.toMatchObject({ statusCode: 401 });
    });
  });
});

