const fs = require('fs');

// Verify all imports in each source file reference valid local modules
const files = [
  'packages/pixelart/src/index.ts',
  'packages/pixelart/src/pixelart-provider.ts',
  'packages/pixelart/src/pixelart-image-model.ts',
  'packages/pixelart/src/pixelart-image-options.ts',
  'packages/pixelart/src/pixelart-image-settings.ts',
  'packages/pixelart/src/version.ts',
];

const localImportRe = /from '\.\/([^']+)'/g;

for (const f of files) {
  const src = fs.readFileSync(f, 'utf8');
  let m;
  while ((m = localImportRe.exec(src)) !== null) {
    const target = require('path').resolve(require('path').dirname(f), m[1] + '.ts');
    if (!fs.existsSync(target)) {
      console.error('MISSING:', target, 'referenced from', f);
      process.exit(1);
    }
  }
}
console.log('All local imports resolve OK');
